27	func (color Ansi) Resolve(current *Set, parents []*Set) Ansi {
28		resolveParentColor := func(keyword Ansi) Ansi {
29			for _, parentColor := range parents {
30				if parentColor == nil {
31					return Transparent
32				}
33	
34				switch keyword {
35				case ParentBackground:
36					keyword = parentColor.Background
37				case ParentForeground:
38					keyword = parentColor.Foreground
39				default:
40					if keyword == "" {
41						return Transparent
42					}
43					return keyword.GradientLast()
44				}
45	
46				if !keyword.IsGradient() {
47					continue
48				}
49	
50				// a parent gradient collapses to its last stop; a keyword stop refers to
51				// that SAME parent's colors, never to the child segment asking for the
52				// parent color. A parentBackground/parentForeground stop walks further up
53				// through the next iteration; an unresolvable self-reference degrades to
54				// transparent instead of leaking a keyword the child would misresolve.
55				stop := keyword.GradientLast()
56	
57				switch stop { //nolint:exhaustive
58				case Foreground:
59					stop = parentColor.Foreground.GradientLast()
60				case Background:
61					stop = parentColor.Background.GradientLast()
62				}
63	
64				if stop.isKeyword() && stop != ParentBackground && stop != ParentForeground && stop != Transparent {
65					return Transparent
66				}
67	
68				keyword = stop
69			}
70	
71			if keyword == "" {
72				return Transparent
73			}
74	
75			return keyword.GradientLast()
76		}
77	
78		resolveKeyword := func(keyword Ansi) Ansi {
79			switch {
80			case keyword == Background && current != nil:
81				return current.Background
82			case keyword == Foreground && current != nil:
83				return current.Foreground
84			case (keyword == ParentBackground || keyword == ParentForeground) && parents != nil:
85				return resolveParentColor(keyword)
86			default:
87				return Transparent
88			}
89		}
90	
91		for color.isKeyword() {
92			resolved := resolveKeyword(color)
