# simulate one cycle's records: primary (1534B gradient-theme size) + transient (328B)
$primary = "x" * 1534
$transient = "y" * 328
$bytes = [System.Text.Encoding]::UTF8.GetBytes($primary + [char]0 + $transient + [char]0)

$iterations = 200

$swOld = [System.Diagnostics.Stopwatch]::StartNew()
for ($i = 0; $i -lt $iterations; $i++) { [void](Invoke-OldReader $bytes) }
$swOld.Stop()

$swNew = [System.Diagnostics.Stopwatch]::StartNew()
for ($i = 0; $i -lt $iterations; $i++) { [void](Invoke-NewReader $bytes 4096) }
$swNew.Stop()

Write-Output ("old: {0:N2} ms/cycle" -f ($swOld.Elapsed.TotalMilliseconds / $iterations))
