package prompt

import (
	"strings"
	"testing"

	"github.com/jandedobbeleer/oh-my-posh/src/cache"
	"github.com/jandedobbeleer/oh-my-posh/src/color"
	"github.com/jandedobbeleer/oh-my-posh/src/maps"
	"github.com/jandedobbeleer/oh-my-posh/src/runtime/mock"
	"github.com/jandedobbeleer/oh-my-posh/src/shell"
	"github.com/jandedobbeleer/oh-my-posh/src/template"
	"github.com/jandedobbeleer/oh-my-posh/src/terminal"

	"github.com/stretchr/testify/assert"
)

func newFillerEngine(t *testing.T) *Engine {
	t.Helper()
	env := new(mock.Environment)
	env.On("Shell").Return(shell.GENERIC)

	engine := &Engine{Env: env}

	template.Cache = &cache.Template{
		SimpleTemplate: cache.SimpleTemplate{Shell: shell.GENERIC},
		Segments:       maps.NewConcurrent[any](),
	}
	template.Init(env, nil, nil)

	terminal.Init(shell.GENERIC)
	terminal.Plain = false
	terminal.Colors = &color.Defaults{}
	terminal.ParentColors = nil

	return engine
}

// Bug 1: an empty-but-non-nil parent stack must degrade to transparent
// (no color), not leak the literal "parentBackground" keyword string.
func TestZZTmpEmptyStackDegradesToTransparent(t *testing.T) {
	engine := newFillerEngine(t)

	// force ParentColors non-nil-but-empty, exactly what terminal.String()
	// leaves behind after a block with segments has rendered once.
	terminal.ParentColors = append(terminal.ParentColors, &color.Set{Background: "#123456"})
	terminal.ParentColors = terminal.ParentColors[:0]

	out, ok := engine.shouldFill("<parentBackground>-</>", 3)
	assert.True(t, ok)
	t.Logf("out = %q", out)
	assert.False(t, strings.Contains(out, "parentBackground"), "must never leak the literal keyword into output: %q", out)
}

// Bug 2: blockTailColors must capture the FULL chain so a filler can walk
// past a tail segment whose own color is itself an unresolved
// parentBackground keyword.
func TestZZTmpFillerChainsThroughUnresolvedTail(t *testing.T) {
	engine := newFillerEngine(t)

	// simulate block [A bg=#FF0000, B bg=parentBackground] having just
	// rendered: A pushed first (tail-first stack), B second, B's own stored
	// color is the unresolved keyword itself.
	terminal.ParentColors = append(terminal.ParentColors,
		&color.Set{Background: "#FF0000", Foreground: "#FFFFFF"},
		&color.Set{Background: color.ParentBackground, Foreground: "#FFFFFF"},
	)

	engine.previousActiveSegment = &config.Segment{} // non-nil so capture doesn't bail
	engine.captureBlockTailColors()

	terminal.ParentColors = nil // simulate String() clearing it for the next block

	out, ok := engine.shouldFill("<parentBackground>-</>", 3)
	assert.True(t, ok)
	t.Logf("out = %q", out)
	assert.True(t, strings.Contains(out, "255;0;0"), "expected to walk past B's unresolved tail to A's red: %q", out)
}
